const userText = msg.payload;
msg.payload = {
  input: {
    brief:
      "Classify this request and extract slots. Return your structured answer as an " +
      "artifact with fields: proceed (boolean — true only if this is a weather-activity " +
      "question), location (string), timeframe (string), activity (string). If it is not " +
      "a weather-activity question, set proceed=false. Request: \"" + userText + "\"",
    context: { userText },
    successCriteria: {
      version: 1,
      gates: [
        {
          id: 'submit-output',
          kind: 'submit-tool-call',
          description: 'Call submit_freeform_output once with the structured slots.',
          required: true
        }
      ]
    }
  }
};
return msg;

// Freeform output puts structured data in state.artifacts; fall back to summary.
const state = msg.payload && msg.payload.state ? msg.payload.state : {};
let slots = {};
const art = Array.isArray(state.artifacts) ? state.artifacts[0] : null;
if (art && typeof art === 'object') slots = art.content || art.data || art;
// Some agents inline JSON in the summary — try to recover it.
if ((slots.proceed === undefined) && typeof state.summary === 'string') {
  const m = state.summary.match(/\{[\s\S]*\}/);
  if (m) { try { slots = JSON.parse(m[0]); } catch (e) {} }
}
msg.intent = slots;
msg.intentTaskId = msg.payload && msg.payload.taskId;
msg.proceed = slots.proceed === true;
return msg;

// Geocoding is out of scope for the demo: a tiny lookup table, default Lyon.
const COORDS = { lyon: [45.76, 4.84], paris: [48.85, 2.35], london: [51.51, -0.13], berlin: [52.52, 13.40] };
const key = String((msg.intent && msg.intent.location) || 'lyon').toLowerCase();
const [lat, lon] = COORDS[key] || COORDS.lyon;
msg.url =
  'https://api.open-meteo.com/v1/forecast?latitude=' + lat + '&longitude=' + lon +
  '&daily=temperature_2m_max,precipitation_probability_max&forecast_days=7&timezone=auto';
return msg;

const forecast = msg.payload; // http response object
msg.payload = {
  input: {
    brief:
      "Given this 7-day forecast and the user's activity, recommend the best day(s) with " +
      "concrete reasoning (temperature, rain probability), or advise against if the weather " +
      "is poor. Be specific about which day and why.",
    context: { intent: msg.intent, forecast }
  },
  references: msg.intentTaskId ? [{ taskId: msg.intentTaskId, role: 'context' }] : []
};
return msg;

const advisor = msg.payload && msg.payload.state ? msg.payload.state : {};
msg.advisorTaskId = msg.payload && msg.payload.taskId;
msg.payload = {
  input: {
    brief:
      "Evaluate the weather recommendation against the rubric. Return an artifact with " +
      "fields: pass (boolean), score (0-1), notes (string). pass=true only if the advice is " +
      "sound, matches the forecast, and is actionable.",
    context: { recommendation: advisor.summary, recommendationArtifacts: advisor.artifacts },
    successCriteria: {
      version: 1,
      gates: [
        {
          id: 'submit-output',
          kind: 'submit-tool-call',
          description: 'Call submit_freeform_output once with the verdict.',
          required: true
        }
      ]
    }
  },
  references: msg.advisorTaskId ? [{ taskId: msg.advisorTaskId, role: 'judged_work' }] : []
};
return msg;

const state = msg.payload && msg.payload.state ? msg.payload.state : {};
let verdict = {};
const art = Array.isArray(state.artifacts) ? state.artifacts[0] : null;
if (art && typeof art === 'object') verdict = art.content || art.data || art;
if ((verdict.pass === undefined) && typeof state.summary === 'string') {
  const m = state.summary.match(/\{[\s\S]*\}/);
  if (m) { try { verdict = JSON.parse(m[0]); } catch (e) {} }
}
msg.verdict = verdict;
msg.pass = verdict.pass === true;
return msg;
